sql:
SELECT title, primary_artist
FROM songs
WHERE release_date > '2000-01-01';

SELECT playlist_id, COUNT(*) AS song_count
FROM playlist_songs
GROUP BY playlist_id;

SELECT title, primary_artist, popularity_score
FROM songs
WHERE primary_artist IN (
    SELECT artist_name
    FROM artists
    WHERE popularity_score > (
        SELECT AVG(popularity_score)
        FROM artists
    )
);

SELECT COUNT(song_id) AS song_count
FROM songs
WHERE album_id = 1;

external_knowledge:
- 'popular tunes' refers to songs; 
- 'how much they've been jammed to' translates to the play count of the songs; 
- 'across all the playlists' indicates the aggregation of play counts from different playlists.
